INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f6c2d3c1-641b-4dba-bdfd-ad3dde3255fd',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kafka Queues — Decoupling, Async Processing, and Load Leveling Explained$escape$,
  $escape$Kafka decouples producers from consumers by writing events to a durable, partitioned log — producers never wait for downstream processing. A payment service publishing to a `transactions` topic has zero knowledge of the fraud-detection consumer reading it; deploy, restart, or scale either side independently.

Async processing drops synchronous latency from your hot path. Instead of calling a notification service inline, publish a `UserSignedUp` event and return HTTP 201 immediately. The consumer processes it on its own schedule.

Load leveling is where Kafka's retention model shines. A burst of 50,000 events/sec can be absorbed into partitions and consumed at a sustainable 5,000 events/sec — the log acts as a shock absorber. Unlike RabbitMQ queues, messages aren't lost after ACK; a consumer can lag behind and catch up without backpressure cascading upstream.

Partition count directly controls max parallelism: 12 partitions → max 12 active consumers in a group. Set `max.poll.records` and `fetch.max.bytes` to tune throughput vs. latency tradeoffs per consumer group.$escape$,
  $escape$import { Kafka } from 'kafkajs';

const kafka = new Kafka({ clientId: 'payment-service', brokers: ['broker:9092'] });
const producer = kafka.producer();

await producer.connect();

// Fire-and-forget: decoupled from fraud-detection consumer
await producer.send({
  topic: 'transactions',
  messages: [{ key: txn.userId, value: JSON.stringify(txn) }],
});

await producer.disconnect();$escape$,
  $escape$typescript$escape$,
