INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ab2223e0-4953-4dbb-9ba6-bddab524c720',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kafka Message Delivery Guarantees — At-Most-Once, At-Least-Once, and Exactly-Once Explained$escape$,
  $escape$Kafka's delivery semantics are controlled by a combination of producer configs, consumer commit strategies, and broker settings — not a single flag.

**At-most-once**: Set `acks=0` on the producer and commit offsets *before* processing. Messages can be lost if the broker crashes or processing fails, but you'll never reprocess.

**At-least-once**: Use `acks=all` with `retries > 0` and commit offsets *after* processing. Duplicates are possible on retry — your consumer logic must be idempotent.

**Exactly-once (EOS)**: Requires `enable.idempotence=true` on the producer (assigns a PID + sequence number, deduped by the broker) and `isolation.level=read_committed` on the consumer. For cross-partition atomicity, use the Kafka Transactions API: `initTransactions()`, `beginTransaction()`, `commitTransaction()`. EOS has ~10–20% throughput overhead and requires Kafka 2.5+ with a 3-broker quorum. In Kafka Streams, set `processing.guarantee=exactly_once_v2` — it wires all of this automatically.$escape$,
  $escape$// Exactly-once producer with Kafka Transactions API (Java)
Properties props = new Properties();
props.put("bootstrap.servers", "localhost:9092");
props.put("enable.idempotence", "true");
props.put("transactional.id", "my-transactional-producer");
props.put("acks", "all");

KafkaProducer<String, String> producer = new KafkaProducer<>(props);
producer.initTransactions();

try {
    producer.beginTransaction();
    producer.send(new ProducerRecord<>("orders", key, value));
    producer.sendOffsetsToTransaction(offsets, new ConsumerGroupMetadata(groupId));
    producer.commitTransaction();
} catch (ProducerFencedException e) {
    producer.close();
} catch (KafkaException e) {
    producer.abortTransaction();
}$escape$,
