INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4e6e59cd-a574-402e-a559-cd058e47a3ef',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kafka Internals — Partitions, Consumer Groups, and Log Compaction Explained$escape$,
  $escape$Each Kafka topic is split into partitions — the unit of parallelism. A partition is an ordered, immutable log; producers append to the tail, consumers read from an offset. Within a consumer group, Kafka assigns each partition to exactly one member, so adding consumers up to the partition count scales throughput linearly. Beyond that, extra consumers sit idle. Offsets are committed to the internal `__consumer_offsets` topic. Use `enable.auto.commit=false` and commit after processing to avoid losing or double-processing messages on rebalance. For at-least-once guarantees, commit post-process; for at-most-once, pre-process. Log compaction (`cleanup.policy=compact`) changes retention semantics: instead of time- or size-based deletion, Kafka retains only the latest record per key, making it ideal for changelog or materialized-view use cases (e.g., Kafka Streams state stores). The cleaner thread runs in the background — `min.cleanable.dirty.ratio` controls how aggressively it compacts. Combine compaction with `delete` policy (`compact,delete`) to support both tombstone deletion and size caps.$escape$,
  $escape$import { Kafka } from 'kafkajs';

const kafka = new Kafka({ brokers: ['localhost:9092'] });
const consumer = kafka.consumer({ groupId: 'inventory-service' });

await consumer.connect();
await consumer.subscribe({ topic: 'product-updates', fromBeginning: false });

await consumer.run({
  eachMessage: async ({ topic, partition, message }) => {
    // Process first, then commit — at-least-once semantics
    await processUpdate(message.value?.toString());
    await consumer.commitOffsets([{
      topic,
      partition,
      offset: (BigInt(message.offset) + 1n).toString(),
    }]);
  },
});$escape$,
