INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c5bf55c0-19f2-4a5b-9612-a6b370206402',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kafka to NATS JetStream — Subjects, Durables, and At-Least-Once Delivery$escape$,
  $escape$Kafka veterans will find NATS JetStream familiar in intent but different in mechanics. Where Kafka uses topics with partitions, NATS uses subjects — dot-delimited strings like `orders.created` or `payments.failed`. JetStream streams are the persistence layer: you bind subject wildcards (`orders.>` captures any depth, `orders.*` captures one token) to a stream, analogous to a Kafka topic absorbing all partition writes.

At-least-once delivery maps directly to JetStream's `AckExplicit` policy — messages redeliver if unacknowledged within `AckWait`, equivalent to Kafka's `enable.auto.commit=false` with manual `commitSync()`. Durable consumers are the JetStream analog of Kafka consumer groups: they track sequence numbers (not byte offsets) and survive client restarts.

The sharpest difference: no partition concept. NATS scales via stream replicas (`Replicas: 3`) and subject filtering rather than sharding. Push consumers handle fan-out; pull consumers give you Kafka-style poll-loop semantics via `Fetch(batch, timeout)` for explicit backpressure control — useful when your downstream processor is rate-limited and you can't absorb unbounded push delivery.$escape$,
  $escape$nc, _ := nats.Connect(nats.DefaultURL)
js, _ := nc.JetStream()

// Equivalent to Kafka CreateTopic — stream binds subject wildcards
js.AddStream(&nats.StreamConfig{
    Name:     "ORDERS",
    Subjects: []string{"orders.>"},
    Replicas: 3,
})

// Durable = Kafka consumer group; AckExplicit = auto.commit false
js.Subscribe("orders.>", func(msg *nats.Msg) {
    process(msg.Data)
    msg.Ack() // skipping Ack → redelivery after AckWait
}, nats.Durable("order-processor"), nats.AckExplicit())$escape$,
  $escape$go$escape$,
