INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f9d2d2af-130a-4797-863d-a5329e9fa170',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kafka vs BullMQ — Offload Scheduled & Prioritized Jobs to Redis Instead$escape$,
  $escape$Kafka excels at high-throughput event streaming, but it has no native concept of job priorities, per-consumer rate limits, or job-level dependencies — patterns that task queues need daily. BullMQ fills that gap using Redis as its backbone.

Priorities let you queue a 'critical' job at level 1 and a background report at level 10 — workers always drain higher-priority buckets first. Rate limiters throttle worker concurrency to N jobs per interval, ideal for wrapping third-party APIs behind your Kafka consumers without backpressure spilling upstream.

Repeatable jobs use a cron expression stored in Redis; unlike a Kafka topic with a retention window, they self-reschedule and skip missed runs cleanly. Job dependencies (parent/child flows) let you model pipelines: a parent job completes only when all its children succeed, giving you DAG semantics without a separate orchestrator.

When your Kafka consumer triggers work that needs retries, scheduling, or fan-out coordination, hand that work off to a BullMQ queue rather than re-publishing to another topic.$escape$,
  $escape$import { Queue, Worker, FlowProducer } from 'bullmq';

const queue = new Queue('reports', { connection: { host: 'localhost', port: 6379 } });

// Priority job — lower number = higher priority
await queue.add('generate-pdf', { userId: 42 }, { priority: 1 });

// Rate-limited worker: max 5 jobs per 10 seconds
const worker = new Worker('reports', async job => {
  console.log('Processing', job.name, job.data);
}, { limiter: { max: 5, duration: 10_000 }, connection: { host: 'localhost', port: 6379 } });

// Repeatable job via cron
await queue.add('weekly-digest', {}, { repeat: { pattern: '0 9 * * MON' } });

// Parent/child dependency flow
const flow = new FlowProducer({ connection: { host: 'localhost', port: 6379 } });
await flow.add({ name: 'send-report', queueName: 'reports', data: {},
  children: [{ name: 'fetch-data', queueName: 'reports', data: { source: 'db' } }] });$escape$,
