INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3f490e78-d578-45cd-ae4d-5e8bb3b80914',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kafka Ordering — Partition Keys Are Your Only Guarantee$escape$,
  $escape$Kafka guarantees message order strictly within a single partition — never across them. Consumers processing different partitions operate independently with no cross-partition sequencing. To enforce ordered processing for a logical entity (an order, a user session, a device), set that entity's ID as the message key. The producer runs the key through murmur2 and consistently routes it to the same partition: same key → same partition → FIFO delivery.

Watch for partition skew: a high-cardinality hotspot key (e.g., a power user) can starve other consumers. Use a compound key like `userId:shardBucket` and mod the bucket count to spread load while preserving intra-entity order.

For global ordering, use a single partition — but you sacrifice all consumer parallelism. That tradeoff almost never makes sense at scale. Instead, model your domain around per-entity ordering: order state machines, device telemetry, and user event streams all fit naturally.

Critically, set `enable.idempotence=true` and `max.in.flight.requests.per.connection=1` on the producer. Without idempotence, a retry on a failed batch can reorder messages within the same partition — silently breaking your ordering guarantee.$escape$,
  $escape$from confluent_kafka import Producer

producer = Producer({
    "bootstrap.servers": "localhost:9092",
    "enable.idempotence": "true",
    "max.in.flight.requests.per.connection": "1",
    "acks": "all",
})

def publish_order_event(order_id: str, payload: bytes) -> None:
    # murmur2(order_id) → deterministic partition assignment
    producer.produce(topic="order-events", key=order_id.encode(), value=payload)
    producer.flush()$escape$,
  $escape$python$escape$,
