INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3e261d76-114a-4b6f-80bd-aecfd2bbf89c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kafka Monitoring — Consumer Lag, Queue Depth, and Dead Letter Alerts That Actually Matter$escape$,
  $escape$Consumer lag is the most critical Kafka metric: it's the delta between the latest offset in a partition and the last committed offset of a consumer group. Fetch it via `kafka.consumer:type=consumer-fetch-manager-metrics,client-id=*` JMX beans, or use the AdminClient API with `listConsumerGroupOffsets()` diff'd against `listOffsets()` for each partition. Alert when lag exceeds your SLA buffer — typically 2–5× your normal processing throughput. For queue depth (log-end-offset), the AdminClient `listOffsets()` with `OffsetSpec.latest()` gives per-partition depth without consuming messages. Dead letter queues in Kafka are conventionally suffixed `.DLT` (Spring Kafka) or `-dlq`. Monitor DLT consumer lag separately — a growing DLT lag means poison pills are accumulating unprocessed. Wire these three signals into Prometheus via `kafka_exporter` (JMX exporter) and set Grafana alerts: lag > threshold for > 2 minutes triggers PagerDuty. Never alert on instantaneous spikes — use a sustained window to avoid noise from rebalances.$escape$,
  $escape$// Fetch consumer group lag per partition using AdminClient
try (AdminClient admin = AdminClient.create(props)) {
    Map<TopicPartition, OffsetAndMetadata> committed =
        admin.listConsumerGroupOffsets("my-group")
             .partitionsToOffsetAndMetadata().get();

    Map<TopicPartition, OffsetSpec> latestReq = committed.keySet().stream()
        .collect(Collectors.toMap(tp -> tp, tp -> OffsetSpec.latest()));

    Map<TopicPartition, ListOffsetsResult.ListOffsetsResultInfo> endOffsets =
        admin.listOffsets(latestReq).all().get();

    committed.forEach((tp, meta) -> {
        long lag = endOffsets.get(tp).offset() - meta.offset();
        System.out.printf("Partition %s lag: %d%n", tp, lag);
    });
}$escape$,
  $escape$kotlin$escape$,
