INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ea6a6956-9936-4e4f-a224-6a405eb6234d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kafka Scaling — Partitions, Consumer Groups, and Rebalancing$escape$,
  $escape$Kafka's parallelism ceiling is your partition count. A consumer group assigns one partition per consumer — if you have 12 partitions and spin up 15 consumers, 3 sit idle. Plan partition count at topic creation; shrinking is unsupported and expanding triggers rebalancing. Rebalancing is Kafka's Achilles heel at scale: every time a consumer joins, leaves, or crashes, the group coordinator pauses all consumption, revokes assignments, and redistributes. With the default `RangeAssignor` and eager protocol, this causes a full stop-the-world pause. Switch to `CooperativeStickyAssignor` and the incremental cooperative rebalancing protocol — only partitions that need to move are revoked, keeping the rest consuming. Tune `max.poll.interval.ms` to match your actual processing time; exceeding it marks the consumer dead and triggers a rebalance. Use `session.timeout.ms` (default 45s) to control how quickly a crashed consumer is detected. For large groups, increase `group.initial.rebalance.delay.ms` so Kafka waits for all consumers to join before assigning, avoiding cascading rebalances at startup.$escape$,
  $escape$const { Kafka } = require('kafkajs');

const kafka = new Kafka({ clientId: 'app', brokers: ['broker:9092'] });

const consumer = kafka.consumer({
  groupId: 'orders-group',
  sessionTimeout: 30000,
  rebalanceTimeout: 60000,
  maxWaitTimeInMs: 5000,
});

await consumer.connect();
await consumer.subscribe({ topic: 'orders', fromBeginning: false });

// CooperativeStickyAssignor requires kafkajs >= 2.x
// Set partitionAssigners in kafka-configs for broker-side
await consumer.run({
  partitionsConsumedConcurrently: 3,
  eachMessage: async ({ topic, partition, message }) => {
    console.log(`[${partition}] ${message.value?.toString()}`);
  },
});$escape$,
  $escape$javascript$escape$,
