INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '66f8ea12-63c1-4963-b936-8b22b5df81a3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kafka Task Patterns — Routing, Beat Scheduling, Result Backends, and Chaining Without Celery$escape$,
  $escape$Kafka replaces Celery's task abstractions with explicit topic-per-concern design. For task routing, dedicate a topic per task type (`email-tasks`, `report-tasks`) and assign separate consumer groups per worker pool — mirrors `task_routes` but gives partition-level parallelism you can scale without redeploying.

Celery Beat has no Kafka native equivalent. Use a Kubernetes CronJob that produces a trigger message to a `scheduled-tasks` topic on schedule. For in-stream scheduling, Kafka Streams' `punctuate()` API fires periodic logic inside a processor topology without an external scheduler.

Result backends: skip Redis. Produce results to a `task-results` topic keyed by `correlation_id`. Use a log-compacted topic so only the latest result per key is retained — callers poll by key with `auto.offset.reset=latest`. No TTL configuration needed.

Task chaining is Kafka's native strength: each processor consumes from one topic, transforms, and produces to the next, forming a linear DAG. With `enable.idempotence=true` and `acks=all`, every hop commits durably before the downstream consumer starts — stronger delivery guarantees than Celery's `chain()` primitive, which can silently drop on broker restart.$escape$,
  $escape$from confluent_kafka import Producer, Consumer
import json, uuid

p = Producer({'bootstrap.servers': 'localhost:9092', 'enable.idempotence': True, 'acks': 'all'})

def dispatch(task_type: str, payload: dict) -> str:
    cid = str(uuid.uuid4())
    p.produce(f"{task_type}-tasks", key=cid, value=json.dumps(payload))
    p.flush()
    return cid  # correlation_id — poll task-results topic by this key

def chain_worker(src: str, dst: str, fn):
    c = Consumer({'bootstrap.servers': 'localhost:9092',
                  'group.id': f'{src}-group', 'auto.offset.reset': 'earliest'})
    c.subscribe([src])
    while True:
        msg = c.poll(1.0)
        if msg and not msg.error():
            p.produce(dst, key=msg.key(), value=json.dumps(fn(json.loads(msg.value()))))
            p.flush()$escape$,
  $escape$python$escape$,
