INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b0b27026-230b-44c6-967d-8baf0bf63ece',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kafka Security — SASL, TLS, and Listener Isolation Done Right$escape$,
  $escape$Kafka brokers support four SASL mechanisms: PLAIN, SCRAM-SHA-256/512, GSSAPI (Kerberos), and OAUTHBEARER. For most cloud deployments, SCRAM-SHA-512 over SASL_SSL is the practical default — it avoids plaintext credential exposure without Kerberos infrastructure complexity. TLS requires ssl.keystore.location and ssl.truststore.location on both brokers and clients; use PEM-formatted certs with ssl.keystore.type=PEM (Kafka 2.7+) to skip JKS entirely.

Listener isolation is non-negotiable: define separate listeners for internal broker-to-broker traffic and external client traffic. Set listeners=INTERNAL://0.0.0.0:9093,EXTERNAL://0.0.0.0:9094 with listener.security.protocol.map=INTERNAL:PLAINTEXT,EXTERNAL:SASL_SSL. Advertised listeners must match listener names exactly or clients will fail to bootstrap with a confusing "Broker not available" error.

Pair authentication with ACLs: kafka-acls.sh --add --allow-principal User:service-account --operation Read --topic payments grants topic-level access. Set authorizer.class.name=kafka.security.authorizer.AclAuthorizer and super.users=User:admin in server.properties. Without ACLs, authenticated users can still read any topic — SASL proves identity, ACLs enforce access. One without the other is half a lock.$escape$,
  $escape$from confluent_kafka import Producer

conf = {
    'bootstrap.servers': 'broker:9094',
    'security.protocol': 'SASL_SSL',
    'sasl.mechanism': 'SCRAM-SHA-512',
    'sasl.username': 'service-account',
    'sasl.password': 's3cr3t',
    'ssl.ca.location': '/etc/kafka/certs/ca.pem',
    'ssl.endpoint.identification.algorithm': 'https',
}

producer = Producer(conf)
producer.produce('payments', key='txn-1', value='{"amount": 100}')
producer.flush()$escape$,
  $escape$python$escape$,
