INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '427e2dc2-6665-4d13-bdf7-75b4ea7adb5d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Kafka vs RabbitMQ vs Redis — A Decision Framework Built Around Kafka's Strengths$escape$,
  $escape$Kafka wins when you need replayability and fan-out: multiple independent consumer groups each maintain their own offsets in the internal `__consumer_offsets` topic, so a billing service and an analytics pipeline can independently consume the same `order-created` topic without interfering. RabbitMQ deletes messages after acknowledgment — no replay, no audit trail. Redis Pub/Sub drops messages entirely if no subscriber is connected at publish time.

Choose RabbitMQ when your workload is task-queue shaped — short-lived jobs, complex routing via exchanges (direct, topic, fanout, headers), and per-message TTL or dead-letter queues without manual Kafka topic plumbing.

Choose Redis Streams when latency is critical (sub-millisecond), data is ephemeral, and throughput fits in memory. `XADD`/`XREADGROUP` gives consumer-group semantics without broker overhead, but durability is limited to your Redis persistence config.

Kafka is the right call for high-throughput event sourcing: set `retention.ms=-1` for infinite log retention, `log.cleanup.policy=compact` for stateful key-based topics, and `enable.idempotence=true` on the producer for exactly-once delivery per partition. Partition count is your parallelism lever — size it to your peak consumer group concurrency.$escape$,
  $escape$from confluent_kafka import Consumer, Producer

# Idempotent producer: exactly-once delivery per partition
producer = Producer({
    "bootstrap.servers": "localhost:9092",
    "enable.idempotence": True,
    "acks": "all",
})

# Independent consumer group: replay without affecting other services
consumer = Consumer({
    "bootstrap.servers": "localhost:9092",
    "group.id": "billing-service",
    "auto.offset.reset": "earliest",   # replay from log start
    "enable.auto.commit": False,        # manual commit for at-least-once
})

consumer.subscribe(["order-created"])
msg = consumer.poll(1.0)
if msg and not msg.error():
    process(msg.value())
    consumer.commit()  # persisted to __consumer_offsets$escape$,
  $escape$python$escape$,
